1	//! # graph-clean
2	//!
3	//! A clean-room reimplementation of the tamarin-prover web-UI constraint-system
4	//! graph payload — the graphviz DOT text served at
5	//! `/thy/trace/N/interactive-graph-def/proof/…`.
6	//!
7	//! Everything here was derived from BLACK-BOX observation of captured payloads
8	//! and live probing of the compiled server; see `workspace/BEHAVIOR.md` for the
9	//! observed spec and `workspace/QUERIES.log` for the oracle interactions. No
10	//! tamarin-prover source was consulted.
11	//!
12	//! ## What it does
13	//! * [`model`] — an independent graph data model (nodes, edges, clusters, legend).
14	//! * [`dot::to_dot`] — a **byte-exact** DOT serializer for that model.
15	//! * [`term`] — a small term model backing abbreviation expansions.
16	//! * [`abbrev`] — node abbreviation: prefix derivation, per-prefix numbering,
17	//!   and byte-exact legend-table HTML.
18	//!
19	//! ## Clustering / simplification trigger
20	//! The compact (clustered) header is used exactly when a graph carries a node
21	//! with a role other than `Undefined`; [`model::Graph::infer_header`] applies
22	//! this observed rule.
23	//!
24	//! ```
25	//! use graph_clean::model::*;
26	//! let mut g = Graph::new(Header::Simple);
27	//! g.push(Stmt::Node(Node::ellipse("n7", Ellipse::new("#vf : isend"))));
28	//! let dot = graph_clean::dot::to_dot(&g);
29	//! assert!(dot.starts_with("digraph \"G\" {\nnodesep=\"0.3\";"));
30	//! assert!(dot.ends_with("\n\n}\n"));
31	//! ```
32	
33	pub mod abbrev;
34	pub mod dot;
35	pub mod model;
36	pub mod term;
37	
38	pub use dot::to_dot;
39	pub use model::{Graph, Header};
40	pub use term::Term;
41

1	//! A minimal term model, sufficient to drive abbreviation (naming + expansion
2	//! rendering). It is an independent design; it renders tamarin-like surface
3	//! syntax for the common term shapes observed in legend expansions
4	//! (variables, constants, pairs, `exp`/`mult`/`union`/`xor`, function apps).
5	//!
6	//! Faithful reproduction of the solver's full term pretty-printer (all operators,
7	//! precedence, line wrapping) is out of scope — see BEHAVIOR.md §3a/§5. The
8	//! covered shapes are byte-tested against captured legend rows.
9	
10	use std::collections::HashMap;
11	
12	/// A term. Variable kinds mirror tamarin's surface decorations.
13	#[derive(Clone, Debug, PartialEq, Eq)]
14	pub enum Term {
15	    /// Fresh variable, rendered `~name`.
16	    Fresh(String),
17	    /// Public variable, rendered `$name`.
18	    Pub(String),
19	    /// Bare message/temporal variable, rendered `name`.
20	    Msg(String),
21	    /// Public constant, rendered `'name'`.
22	    Const(String),
23	    /// Right-nested pair; rendered flattened as `<a, b, c>`.
24	    Pair(Box<Term>, Box<Term>),
25	    /// `exp(base, e)`, rendered `base^e` (the exponent carries its own parens
26	    /// when it is a product/sum).
27	    Exp(Box<Term>, Box<Term>),
28	    /// An associative-commutative operator rendered infix inside parentheses:
29	    /// `mult`→`*`, `union`→`++`, `xor`→`⊕`. `func` is the logical name used for
30	    /// the abbreviation prefix.
31	    Ac { func: String, op: String, args: Vec<Term> },
32	    /// Ordinary prefix application `func(a, b, …)`.
33	    App { func: String, args: Vec<Term> },
34	}
35	
36	impl Term {
37	    // ---- convenience constructors --------------------------------------
38	
39	    pub fn fresh(n: &str) -> Term {
40	        Term::Fresh(n.to_string())
41	    }
42	    pub fn pubv(n: &str) -> Term {
43	        Term::Pub(n.to_string())
44	    }
45	    pub fn msg(n: &str) -> Term {
46	        Term::Msg(n.to_string())
47	    }
48	    pub fn cst(n: &str) -> Term {
49	        Term::Const(n.to_string())
50	    }
51	    pub fn app(func: &str, args: Vec<Term>) -> Term {
52	        Term::App { func: func.to_string(), args }
53	    }
54	    pub fn exp(base: Term, e: Term) -> Term {
55	        Term::Exp(Box::new(base), Box::new(e))
56	    }
57	    pub fn mult(args: Vec<Term>) -> Term {
58	        Term::Ac { func: "mult".into(), op: "*".into(), args }
59	    }
60	    pub fn union(args: Vec<Term>) -> Term {
61	        Term::Ac { func: "union".into(), op: "++".into(), args }
62	    }
63	    pub fn xor(args: Vec<Term>) -> Term {
64	        Term::Ac { func: "xor".into(), op: "\u{2295}".into(), args }
65	    }
66	    /// Build a flattened tuple `<a, b, c>` from ≥1 elements (right-nested pairs).
67	    pub fn tuple(mut elems: Vec<Term>) -> Term {
68	        let last = elems.pop().expect("tuple needs ≥1 element");
69	        elems.into_iter().rev().fold(last, |acc, e| Term::Pair(Box::new(e), Box::new(acc)))
70	    }
71	
72	    // ---- naming --------------------------------------------------------
73	
74	    /// The root symbol's *name*, whose first two letters give the abbreviation
75	    /// prefix (see [`crate::abbrev::prefix_for_symbol`]).
76	    pub fn root_symbol_name(&self) -> String {
77	        match self {
78	            Term::Fresh(n) | Term::Pub(n) | Term::Msg(n) | Term::Const(n) => n.clone(),
79	            Term::Pair(..) => "pair".to_string(),
80	            Term::Exp(..) => "exp".to_string(),
81	            Term::Ac { func, .. } => func.clone(),
82	            Term::App { func, .. } => func.clone(),
83	        }
84	    }
85	
86	    /// Leaf terms (variables/constants) are atomic; everything else is not.
87	    pub fn is_atomic(&self) -> bool {
88	        matches!(self, Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_))
89	    }
90	
91	    /// A tuple / pair `<a, b, …>`. Tuples are never abbreviated (BEHAVIOR.md §5c,
92	    /// observed: 0 of 97 538 legend entries is a top-level tuple, and a live probe
93	    /// left a length-18 tuple occurring twice un-abbreviated).
94	    pub fn is_tuple(&self) -> bool {
95	        matches!(self, Term::Pair(..))
96	    }
97	
98	    /// Number of Unicode scalar values in the fully-expanded surface rendering —
99	    /// the measure that gates abbreviation (BEHAVIOR.md §5c). This counts the
100	    /// surface decorations too (`'…'` quotes, `~`/`$` sigils), matching the
101	    /// observed boundary (`'12345678'` = 10 chars is abbreviated, `'1234567'` = 9
102	    /// is not).
103	    pub fn render_len(&self) -> usize {
104	        self.render_full().chars().count()
105	    }
106	
107	    /// Number of term nodes (atoms + operators) — a simple complexity measure.
108	    pub fn size(&self) -> usize {
109	        match self {
110	            Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_) => 1,
111	            Term::Pair(a, b) => 1 + a.size() + b.size(),
112	            Term::Exp(a, b) => 1 + a.size() + b.size(),
113	            Term::Ac { args, .. } | Term::App { args, .. } => {
114	                1 + args.iter().map(Term::size).sum::<usize>()
115	            }
116	        }
117	    }
118	
119	    /// Visit this term and every sub-term (pre-order).
120	    pub fn for_each_subterm(&self, f: &mut dyn FnMut(&Term)) {
121	        f(self);
122	        match self {
123	            Term::Pair(a, b) | Term::Exp(a, b) => {
124	                a.for_each_subterm(f);
125	                b.for_each_subterm(f);
126	            }
127	            Term::Ac { args, .. } | Term::App { args, .. } => {
128	                for a in args {
129	                    a.for_each_subterm(f);
130	                }
131	            }
132	            _ => {}
133	        }
134	    }
135	
136	    // ---- rendering -----------------------------------------------------
137	
138	    /// Fully-expanded surface rendering (no abbreviations). Used as the dedup key.
139	    pub fn render_full(&self) -> String {
140	        self.render_with(&|t| t.render_full())
141	    }
142	
143	    /// Render this term's expansion, replacing any *registered* sub-term (present
144	    /// in `table`, keyed by its full rendering) with its abbreviation name. The
145	    /// top-level term itself is always rendered structurally.
146	    pub fn render_abbrev(&self, table: &HashMap<String, String>) -> String {
147	        self.render_with(&|t| t.substitute(table))
148	    }
149	
150	    /// Rendering used for children during abbreviation: a registered term yields
151	    /// its name, otherwise it renders structurally (recursing on its children).
152	    fn substitute(&self, table: &HashMap<String, String>) -> String {
153	        if let Some(name) = table.get(&self.render_full()) {
154	            return name.clone();
155	        }
156	        self.render_with(&|t| t.substitute(table))
157	    }
158	
159	    /// Structural rendering; `child` renders each immediate sub-term.
160	    fn render_with(&self, child: &dyn Fn(&Term) -> String) -> String {
161	        match self {
162	            Term::Fresh(n) => format!("~{}", n),
163	            Term::Pub(n) => format!("${}", n),
164	            Term::Msg(n) => n.clone(),
165	            Term::Const(n) => format!("'{}'", n),
166	            Term::Pair(..) => {
167	                let elems = self.pair_spine();
168	                let parts: Vec<String> = elems.iter().map(|t| child(t)).collect();
169	                format!("<{}>", parts.join(", "))
170	            }
171	            Term::Exp(base, e) => format!("{}^{}", child(base), child(e)),
172	            Term::Ac { op, args, .. } => {
173	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
174	                format!("({})", parts.join(op))
175	            }
176	            Term::App { func, args } => {
177	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
178	                format!("{}({})", func, parts.join(", "))
179	            }
180	        }
181	    }
182	
183	    /// Flatten a right-nested pair into its element spine.
184	    fn pair_spine(&self) -> Vec<&Term> {
185	        let mut out = Vec::new();
186	        let mut cur = self;
187	        while let Term::Pair(a, b) = cur {
188	            out.push(a.as_ref());
189	            cur = b.as_ref();
190	        }
191	        out.push(cur);
192	        out
193	    }
194	}
195

1	//! Graph data model for the tamarin web-UI constraint-system graph.
2	//!
3	//! This is an independent model designed from the observed DOT payloads
4	//! (see workspace/BEHAVIOR.md). A [`Graph`] is an ordered list of top-level
5	//! [`Stmt`]s rendered under one of two header styles. The [`crate::dot`]
6	//! serializer turns a `Graph` back into byte-exact DOT text.
7	
8	/// Which top-level attribute header to emit.
9	///
10	/// Per the observed trigger rule (BEHAVIOR.md §4), [`Header::Compact`] is used
11	/// exactly when the graph carries a node with a non-`Undefined` role; otherwise
12	/// [`Header::Simple`]. [`Graph::infer_header`] applies that rule.
13	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
14	pub enum Header {
15	    /// Plain multiset-rewriting graph header (`nodesep="0.3"`, …).
16	    Simple,
17	    /// Clustered/process graph header (`packmode="cluster"`, `compound="true"`, …).
18	    Compact,
19	}
20	
21	/// The role annotation carried by a record node.
22	///
23	/// `Undefined` is the sentinel for plain multiset-rewriting rules; any other
24	/// value denotes a process/agent role and triggers clustering.
25	#[derive(Clone, Debug, PartialEq, Eq)]
26	pub struct Role(pub String);
27	
28	impl Role {
29	    pub const UNDEFINED: &'static str = "Undefined";
30	    pub fn undefined() -> Self {
31	        Role(Self::UNDEFINED.to_string())
32	    }
33	    pub fn is_undefined(&self) -> bool {
34	        self.0 == Self::UNDEFINED
35	    }
36	}
37	
38	/// A whole graph: the two node/edge default lines are chosen by `header`, and
39	/// `body` holds every statement in emission order.
40	#[derive(Clone, Debug)]
41	pub struct Graph {
42	    pub header: Header,
43	    pub body: Vec<Stmt>,
44	}
45	
46	impl Graph {
47	    pub fn new(header: Header) -> Self {
48	        Graph { header, body: Vec::new() }
49	    }
50	
51	    pub fn push(&mut self, s: Stmt) -> &mut Self {
52	        self.body.push(s);
53	        self
54	    }
55	
56	    /// Apply the observed clustering trigger (BEHAVIOR.md §4): compact iff any
57	    /// record node anywhere in the graph has a non-`Undefined` role.
58	    pub fn infer_header(&self) -> Header {
59	        if self.body.iter().any(stmt_has_role_node) {
60	            Header::Compact
61	        } else {
62	            Header::Simple
63	        }
64	    }
65	
66	    /// Set `header` to the inferred value.
67	    pub fn set_inferred_header(&mut self) {
68	        self.header = self.infer_header();
69	    }
70	}
71	
72	fn stmt_has_role_node(s: &Stmt) -> bool {
73	    match s {
74	        Stmt::Node(n) => n.has_defined_role(),
75	        Stmt::Cluster(c) => c.body.iter().any(stmt_has_role_node),
76	        Stmt::RankBlock(b) => b.body.iter().any(stmt_has_role_node),
77	        Stmt::Edge(_) => false,
78	    }
79	}
80	
81	/// A top-level (or nested) statement, emitted in list order.
82	#[derive(Clone, Debug)]
83	pub enum Stmt {
84	    Node(Node),
85	    Edge(Edge),
86	    /// A `subgraph "cluster_…" { … }` block (compact/clustered mode).
87	    Cluster(Cluster),
88	    /// An anonymous `{ rank="sink"; … }` block (used for the legend).
89	    RankBlock(RankBlock),
90	}
91	
92	/// A DOT node statement. `id` is the full graphviz identifier verbatim, e.g.
93	/// `"n5"`. Ports ([`Cell::port`]) and edge endpoints ([`EndPoint`]) use the same
94	/// full-string convention (`"n2"`), so the serializer emits ids as given.
95	#[derive(Clone, Debug)]
96	pub struct Node {
97	    pub id: String,
98	    pub kind: NodeKind,
99	}
100	
101	impl Node {
102	    pub fn record(id: impl Into<String>, r: Record) -> Self {
103	        Node { id: id.into(), kind: NodeKind::Record(r) }
104	    }
105	    pub fn ellipse(id: impl Into<String>, e: Ellipse) -> Self {
106	        Node { id: id.into(), kind: NodeKind::Ellipse(e) }
107	    }
108	    pub fn plain(id: impl Into<String>, html: impl Into<String>) -> Self {
109	        Node { id: id.into(), kind: NodeKind::Plain { html: html.into() } }
110	    }
111	    pub fn has_defined_role(&self) -> bool {
112	        matches!(&self.kind, NodeKind::Record(r) if !r.role.is_undefined())
113	    }
114	}
115	
116	#[derive(Clone, Debug)]
117	pub enum NodeKind {
118	    /// Rule / graph-node instance drawn as a graphviz record.
119	    Record(Record),
120	    /// Atomic knowledge / action / temporal node drawn as an ellipse.
121	    Ellipse(Ellipse),
122	    /// The abbreviation legend, an HTML-like label. `html` is the inner content
123	    /// between `label=<` and `>` (i.e. it starts with `<TABLE …`).
124	    Plain { html: String },
125	}
126	
127	/// A record node's label and styling. `columns` are the top-level record groups
128	/// (`{…}|{…}|{…}`, typically premises / rule-info / conclusions); each column is
129	/// a list of ported cells joined by `|`.
130	#[derive(Clone, Debug)]
131	pub struct Record {
132	    pub columns: Vec<Vec<Cell>>,
133	    pub fillcolor: String,
134	    pub fontcolor: String,
135	    pub role: Role,
136	}
137	
138	/// One ported record cell: `<n{port}> {text}`. `text` is taken pre-rendered
139	/// (already escaped/wrapped); see BEHAVIOR.md §3a on why wrapping is a gap.
140	#[derive(Clone, Debug)]
141	pub struct Cell {
142	    pub port: String,
143	    pub text: String,
144	}
145	
146	impl Cell {
147	    pub fn new(port: impl Into<String>, text: impl Into<String>) -> Self {
148	        Cell { port: port.into(), text: text.into() }
149	    }
150	}
151	
152	#[derive(Clone, Debug)]
153	pub struct Ellipse {
154	    pub label: String,
155	    pub color: Option<String>,
156	}
157	
158	impl Ellipse {
159	    pub fn new(label: impl Into<String>) -> Self {
160	        Ellipse { label: label.into(), color: None }
161	    }
162	    pub fn colored(label: impl Into<String>, color: impl Into<String>) -> Self {
163	        Ellipse { label: label.into(), color: Some(color.into()) }
164	    }
165	}
166	
167	/// One endpoint of an edge: node id plus optional record port.
168	#[derive(Clone, Debug)]
169	pub struct EndPoint {
170	    pub node: String,
171	    pub port: Option<String>,
172	}
173	
174	impl EndPoint {
175	    pub fn node(node: impl Into<String>) -> Self {
176	        EndPoint { node: node.into(), port: None }
177	    }
178	    pub fn port(node: impl Into<String>, port: impl Into<String>) -> Self {
179	        EndPoint { node: node.into(), port: Some(port.into()) }
180	    }
181	}
182	
183	/// An edge statement. `attrs` are `(key, value)` pairs emitted in list order as
184	/// `[k="v",…]` (see BEHAVIOR.md §3c for the observed style vocabulary).
185	#[derive(Clone, Debug)]
186	pub struct Edge {
187	    pub src: EndPoint,
188	    pub dst: EndPoint,
189	    pub attrs: Vec<(String, String)>,
190	}
191	
192	impl Edge {
193	    pub fn new(src: EndPoint, dst: EndPoint, attrs: &[(&str, &str)]) -> Self {
194	        Edge {
195	            src,
196	            dst,
197	            attrs: attrs.iter().map(|(k, v)| (k.to_string(), v.to_string())).collect(),
198	        }
199	    }
200	}
201	
202	/// A `subgraph "cluster_…" { … }` block.
203	#[derive(Clone, Debug)]
204	pub struct Cluster {
205	    /// The cluster label WITHOUT the `cluster_` prefix (e.g. `Initiator_Session_1`).
206	    pub label: String,
207	    /// 8-hex ARGB used for both `color` and `fillcolor` (e.g. `#4936D84C`).
208	    pub color: String,
209	    pub body: Vec<Stmt>,
210	}
211	
212	/// An anonymous block carrying a `rank` and inner statements — used for the
213	/// legend's `{ rank="sink"; … }`.
214	#[derive(Clone, Debug)]
215	pub struct RankBlock {
216	    pub rank: String,
217	    pub body: Vec<Stmt>,
218	}
219

1	//! Byte-exact DOT serializer for [`Graph`].
2	//!
3	//! Reproduces the exact bytes the tamarin web UI emits at
4	//! `interactive-graph-def` (see workspace/BEHAVIOR.md §2, §3). The emission is
5	//! driven by one structural rule: every block is
6	//! `OPEN "\n"` + (each inner line + `"\n"`) + `"\n}"`, i.e. one blank line before
7	//! the closing brace; the top-level digraph then gets a final `"\n"`.
8	
9	use crate::model::*;
10	
11	/// Serialize a graph to DOT text (byte-exact against captured payloads).
12	pub fn to_dot(g: &Graph) -> String {
13	    let mut lines: Vec<String> = header_lines(g.header);
14	    for s in &g.body {
15	        lines.push(render_stmt(s));
16	    }
17	    // Top-level digraph block, plus the trailing newline the server emits.
18	    let mut out = render_block("digraph \"G\" {", &lines);
19	    out.push('\n');
20	    out
21	}
22	
23	/// `OPEN\n` + `line\n`* + `\n}`  (no trailing newline; callers add it if needed).
24	/// A `line` may itself be multi-line (a nested block); the per-line `\n` after it
25	/// supplies the separator the parent owes it.
26	fn render_block(open: &str, lines: &[String]) -> String {
27	    let mut s = String::new();
28	    s.push_str(open);
29	    s.push('\n');
30	    for l in lines {
31	        s.push_str(l);
32	        s.push('\n');
33	    }
34	    s.push_str("\n}");
35	    s
36	}
37	
38	fn header_lines(h: Header) -> Vec<String> {
39	    let raw: &[&str] = match h {
40	        Header::Simple => &[
41	            "nodesep=\"0.3\";",
42	            "ranksep=\"0.3\";",
43	            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\"];",
44	            "edge[fontsize=\"8\",fontname=\"Helvetica\"];",
45	        ],
46	        Header::Compact => &[
47	            "nodesep=\"0.8\";",
48	            "ranksep=\"0.8\";",
49	            "sep=\"4\";",
50	            "splines=\"true\";",
51	            "overlap=\"false\";",
52	            "pack=\"true\";",
53	            "packmode=\"cluster\";",
54	            "concentrate=\"true\";",
55	            "compound=\"true\";",
56	            "remincross=\"true\";",
57	            "mclimit=\"10\";",
58	            "nslimit=\"20\";",
59	            "nslimit1=\"20\";",
60	            "ordering=\"out\";",
61	            "rankdir=\"TB\";",
62	            "showboxes=\"false\";",
63	            "clusterrank=\"local\";",
64	            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\",margin=\"0.05,0.05\",shape=\"ellipse\"];",
65	            "edge[fontsize=\"8\",fontname=\"Helvetica\",penwidth=\"1.5\",arrowsize=\"0.5\",color=\"black\",style=\"solid\",weight=\"8\"];",
66	        ],
67	    };
68	    raw.iter().map(|s| s.to_string()).collect()
69	}
70	
71	fn render_stmt(s: &Stmt) -> String {
72	    match s {
73	        Stmt::Node(n) => render_node(n),
74	        Stmt::Edge(e) => render_edge(e),
75	        Stmt::Cluster(c) => render_cluster(c),
76	        Stmt::RankBlock(b) => render_rankblock(b),
77	    }
78	}
79	
80	fn render_node(n: &Node) -> String {
81	    match &n.kind {
82	        NodeKind::Record(r) => {
83	            format!(
84	                "{}[shape=\"record\",label=\"{}\",fillcolor=\"{}\",style=\"filled\",fontcolor=\"{}\",role=\"{}\"];",
85	                n.id,
86	                render_record_label(r),
87	                r.fillcolor,
88	                r.fontcolor,
89	                r.role.0,
90	            )
91	        }
92	        NodeKind::Ellipse(e) => match &e.color {
93	            Some(c) => format!(
94	                "{}[label=\"{}\",shape=\"ellipse\",color=\"{}\"];",
95	                n.id, e.label, c
96	            ),
97	            None => format!("{}[label=\"{}\",shape=\"ellipse\"];", n.id, e.label),
98	        },
99	        NodeKind::Plain { html } => {
100	            format!("{}[shape=\"plain\",label=<{}>];", n.id, html)
101	        }
102	    }
103	}
104	
105	/// `{{<p> t|<p> t}|{<p> t}|{<p> t|<p> t}}` — outer braces, groups joined by `|`,
106	/// each group `{cell|cell}`, each cell `<port> text`.
107	fn render_record_label(r: &Record) -> String {
108	    let mut s = String::from("{");
109	    let groups: Vec<String> = r
110	        .columns
111	        .iter()
112	        .map(|col| {
113	            let cells: Vec<String> = col
114	                .iter()
115	                .map(|c| format!("<{}> {}", c.port, c.text))
116	                .collect();
117	            format!("{{{}}}", cells.join("|"))
118	        })
119	        .collect();
120	    s.push_str(&groups.join("|"));
121	    s.push('}');
122	    s
123	}
124	
125	fn render_edge(e: &Edge) -> String {
126	    let mut s = render_endpoint(&e.src);
127	    s.push_str(" -> ");
128	    s.push_str(&render_endpoint(&e.dst));
129	    if !e.attrs.is_empty() {
130	        let attrs: Vec<String> = e
131	            .attrs
132	            .iter()
133	            .map(|(k, v)| format!("{}=\"{}\"", k, v))
134	            .collect();
135	        s.push('[');
136	        s.push_str(&attrs.join(","));
137	        s.push(']');
138	    }
139	    s.push(';');
140	    s
141	}
142	
143	fn render_endpoint(ep: &EndPoint) -> String {
144	    match &ep.port {
145	        Some(p) => format!("{}:{}", ep.node, p),
146	        None => ep.node.clone(),
147	    }
148	}
149	
150	fn render_cluster(c: &Cluster) -> String {
151	    let mut lines = vec![
152	        "nodesep=\"0.6\";".to_string(),
153	        "ranksep=\"0.6\";".to_string(),
154	        format!("label=\"{}\";", c.label),
155	        "style=\"filled\";".to_string(),
156	        format!("color=\"{}\";", c.color),
157	        "penwidth=\"2\";".to_string(),
158	        format!("fillcolor=\"{}\";", c.color),
159	        "overlap=\"false\";".to_string(),
160	        "sep=\"4\";".to_string(),
161	    ];
162	    for s in &c.body {
163	        lines.push(render_stmt(s));
164	    }
165	    let open = format!("subgraph \"cluster_{}\" {{", c.label);
166	    render_block(&open, &lines)
167	}
168	
169	fn render_rankblock(b: &RankBlock) -> String {
170	    let mut lines = vec![format!("rank=\"{}\";", b.rank)];
171	    for s in &b.body {
172	        lines.push(render_stmt(s));
173	    }
174	    render_block("{", &lines)
175	}
