1	//! Byte-parity round-trip tests against captured DOT payloads.
2	//!
3	//! A minimal parser for the exact DOT dialect the tamarin web UI emits reads
4	//! each captured fixture into the crate's own [`Graph`] model; re-serializing
5	//! with [`graph_clean::dot::to_dot`] must reproduce the original bytes exactly.
6	//! This validates the payload-format spec (BEHAVIOR.md §2, §3) end to end.
7	
8	use graph_clean::dot::to_dot;
9	use graph_clean::model::*;
10	
11	// ----------------------------------------------------------------------------
12	// Parser for the captured DOT dialect (test-only ingest).
13	// ----------------------------------------------------------------------------
14	
15	/// Merge a plain-node legend that spans several physical lines into one logical
16	/// line, so every statement is a single element.
17	fn logical_lines(dot: &str) -> Vec<String> {
18	    let raw: Vec<&str> = dot.split('\n').collect();
19	    let mut out: Vec<String> = Vec::new();
20	    let mut i = 0;
21	    while i < raw.len() {
22	        let line = raw[i];
23	        if line.contains("shape=\"plain\"") && !line.trim_end().ends_with("];") {
24	            let mut buf = String::from(line);
25	            i += 1;
26	            loop {
27	                buf.push('\n');
28	                buf.push_str(raw[i]);
29	                if raw[i].trim_end().ends_with("];") {
30	                    break;
31	                }
32	                i += 1;
33	            }
34	            out.push(buf);
35	            i += 1;
36	        } else {
37	            out.push(line.to_string());
38	            i += 1;
39	        }
40	    }
41	    out
42	}
43	
44	fn parse(dot: &str) -> Graph {
45	    let lines = logical_lines(dot);
46	    let header = if lines.iter().any(|l| l == "packmode=\"cluster\";") {
47	        Header::Compact
48	    } else {
49	        Header::Simple
50	    };
51	    // Body is everything strictly inside the outermost `digraph "G" {` … `}`.
52	    let mut idx = lines.iter().position(|l| l == "digraph \"G\" {").unwrap() + 1;
53	    let mut g = Graph::new(header);
54	    g.body = parse_block(&lines, &mut idx);
55	    g
56	}
57	
58	/// Parse statements until the matching `}` (which it consumes). `idx` points at
59	/// the first inner line.
60	fn parse_block(lines: &[String], idx: &mut usize) -> Vec<Stmt> {
61	    let mut out = Vec::new();
62	    while *idx < lines.len() {
63	        let line = lines[*idx].clone();
64	        let trimmed = line.trim_end();
65	        if trimmed == "}" {
66	            *idx += 1;
67	            return out;
68	        }
69	        if trimmed.is_empty() || is_block_attr(trimmed) {
70	            *idx += 1;
71	            continue;
72	        }
73	        if trimmed.starts_with("subgraph \"cluster_") {
74	            let label = trimmed
75	                .trim_start_matches("subgraph \"cluster_")
76	                .trim_end_matches("\" {")
77	                .to_string();
78	            *idx += 1;
79	            // capture color, then inner nodes
80	            let color = capture_attr(lines, *idx, "color").unwrap();
81	            let body = parse_block(lines, idx);
82	            out.push(Stmt::Cluster(Cluster { label, color, body }));
83	            continue;
84	        }
85	        if trimmed == "{" {
86	            *idx += 1;
87	            let rank = capture_attr(lines, *idx, "rank").unwrap();
88	            let body = parse_block(lines, idx);
89	            out.push(Stmt::RankBlock(RankBlock { rank, body }));
90	            continue;
91	        }
92	        // node or edge statement (single logical line)
93	        if line.contains(" -> ") {
94	            out.push(Stmt::Edge(parse_edge(&line)));
95	        } else {
96	            out.push(Stmt::Node(parse_node(&line)));
97	        }
98	        *idx += 1;
99	    }
100	    out
101	}
102	
103	/// True for lines that are block attributes (regenerated by the serializer, so
104	/// dropped on ingest).
105	fn is_block_attr(l: &str) -> bool {
106	    if l.starts_with("node[") || l.starts_with("edge[") {
107	        return true;
108	    }
109	    // key="..."; where key is lowercase — but NOT a node/edge stmt (those have '[').
110	    if l.contains('[') {
111	        return false;
112	    }
113	    if let Some(eq) = l.find('=') {
114	        let key = &l[..eq];
115	        return key.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit())
116	            && l.ends_with(';');
117	    }
118	    false
119	}
120	
121	fn capture_attr(lines: &[String], from: usize, key: &str) -> Option<String> {
122	    let needle = format!("{}=\"", key);
123	    for l in &lines[from..] {
124	        let t = l.trim();
125	        if t.starts_with(&needle) {
126	            let rest = &t[needle.len()..];
127	            return Some(rest.trim_end_matches("\";").trim_end_matches('"').to_string());
128	        }
129	        if t == "}" {
130	            break;
131	        }
132	    }
133	    None
134	}
135	
136	fn parse_node(line: &str) -> Node {
137	    let l = line.trim_end();
138	    let br = l.find('[').unwrap();
139	    let id = l[..br].to_string();
140	    let attrs = &l[br + 1..l.rfind("];").unwrap()];
141	    if attrs.starts_with("shape=\"record\"") {
142	        // shape="record",label="…",fillcolor="…",style="filled",fontcolor="…",role="…"
143	        let label_start = l.find(",label=\"").unwrap() + ",label=\"".len();
144	        let label_end = l.find("\",fillcolor=\"").unwrap();
145	        let label = &l[label_start..label_end];
146	        let fillcolor = extract(l, "fillcolor=\"");
147	        let fontcolor = extract(l, "fontcolor=\"");
148	        let role = extract(l, "role=\"");
149	        Node::record(
150	            id,
151	            Record {
152	                columns: parse_record_label(label),
153	                fillcolor,
154	                fontcolor,
155	                role: Role(role),
156	            },
157	        )
158	    } else if attrs.starts_with("shape=\"plain\"") {
159	        let start = l.find("label=<").unwrap() + "label=<".len();
160	        let end = l.rfind(">];").unwrap();
161	        Node::plain(id, &l[start..end])
162	    } else {
163	        // ellipse: label="…",shape="ellipse"[,color="…"]
164	        let label_start = l.find("label=\"").unwrap() + "label=\"".len();
165	        let label_end = l.find("\",shape=\"ellipse\"").unwrap();
166	        let label = l[label_start..label_end].to_string();
167	        let color = if l.contains(",color=\"") {
168	            Some(extract(l, ",color=\""))
169	        } else {
170	            None
171	        };
172	        Node::ellipse(id, Ellipse { label, color })
173	    }
174	}
175	
176	fn extract(l: &str, key: &str) -> String {
177	    let s = l.find(key).unwrap() + key.len();
178	    let rest = &l[s..];
179	    let e = rest.find('"').unwrap();
180	    rest[..e].to_string()
181	}
182	
183	/// `{{<p> t|<p> t}|{<p> t}|…}` → columns of ported cells.
184	fn parse_record_label(s: &str) -> Vec<Vec<Cell>> {
185	    let inner = &s[1..s.len() - 1]; // strip outer { }
186	    split_top(inner, '|')
187	        .into_iter()
188	        .map(|group| {
189	            let g = &group[1..group.len() - 1]; // strip group { }
190	            split_top(g, '|')
191	                .into_iter()
192	                .map(|cell| parse_cell(&cell))
193	                .collect()
194	        })
195	        .collect()
196	}
197	
198	fn parse_cell(cell: &str) -> Cell {
199	    // `<port> text`
200	    let gt = find_unescaped(cell, '>').unwrap();
201	    let port = cell[1..gt].to_string();
202	    let text = cell[gt + 2..].to_string(); // skip "> "
203	    Cell { port, text }
204	}
205	
206	/// Split on `sep` at brace-depth 0, honoring backslash escapes.
207	fn split_top(s: &str, sep: char) -> Vec<String> {
208	    let mut parts = Vec::new();
209	    let mut depth = 0i32;
210	    let mut cur = String::new();
211	    let mut esc = false;
212	    for c in s.chars() {
213	        if esc {
214	            cur.push(c);
215	            esc = false;
216	            continue;
217	        }
218	        match c {
219	            '\\' => {
220	                cur.push(c);
221	                esc = true;
222	            }
223	            '{' => {
224	                depth += 1;
225	                cur.push(c);
226	            }
227	            '}' => {
228	                depth -= 1;
229	                cur.push(c);
230	            }
231	            _ if c == sep && depth == 0 => {
232	                parts.push(std::mem::take(&mut cur));
233	            }
234	            _ => cur.push(c),
235	        }
236	    }
237	    parts.push(cur);
238	    parts
239	}
240	
241	fn find_unescaped(s: &str, target: char) -> Option<usize> {
242	    let mut esc = false;
243	    for (i, c) in s.char_indices() {
244	        if esc {
245	            esc = false;
246	            continue;
247	        }
248	        if c == '\\' {
249	            esc = true;
250	        } else if c == target {
251	            return Some(i);
252	        }
253	    }
254	    None
255	}
256	
257	fn parse_edge(line: &str) -> Edge {
258	    let l = line.trim_end().trim_end_matches(';');
259	    let arrow = l.find(" -> ").unwrap();
260	    let src = parse_endpoint(&l[..arrow]);
261	    let rest = &l[arrow + 4..];
262	    let (dst_str, attrs) = match rest.find('[') {
263	        Some(b) => (&rest[..b], parse_attrs(&rest[b + 1..rest.rfind(']').unwrap()])),
264	        None => (rest, Vec::new()),
265	    };
266	    Edge {
267	        src,
268	        dst: parse_endpoint(dst_str),
269	        attrs,
270	    }
271	}
272	
273	fn parse_endpoint(s: &str) -> EndPoint {
274	    match s.find(':') {
275	        Some(c) => EndPoint::port(s[..c].to_string(), s[c + 1..].to_string()),
276	        None => EndPoint::node(s.to_string()),
277	    }
278	}
279	
280	fn parse_attrs(s: &str) -> Vec<(String, String)> {
281	    // k="v",k="v",…
282	    let mut out = Vec::new();
283	    for part in s.split("\",") {
284	        let part = part.trim_end_matches('"');
285	        if let Some(eq) = part.find("=\"") {
286	            out.push((part[..eq].to_string(), part[eq + 2..].to_string()));
287	        }
288	    }
289	    out
290	}
291	
