293	// Tests
294	// ----------------------------------------------------------------------------
295	
296	fn check(name: &str, dot: &str) {
297	    let g = parse(dot);
298	    let out = to_dot(&g);
299	    assert_eq!(out, dot, "byte round-trip mismatch for fixture {name}");
300	    // The inferred header must match what the fixture actually uses.
301	    assert_eq!(g.infer_header(), g.header, "header trigger mismatch for {name}");
302	}
