334	/// Bulk generalization check (off by default). Set `GRAPHCLEAN_CORPUS` to a
335	/// directory of captured `*.dot` payloads; every one must round-trip byte-exact.
336	/// Used to measure how general the format model is beyond the 6 committed
337	/// fixtures; prints a summary and fails if any file mismatches.
338	#[test]
339	fn roundtrip_corpus_dir() {
340	    let Ok(dir) = std::env::var("GRAPHCLEAN_CORPUS") else {
341	        return;
342	    };
343	    let mut total = 0usize;
344	    let mut ok = 0usize;
345	    let mut fails: Vec<String> = Vec::new();
346	    for entry in std::fs::read_dir(&dir).unwrap() {
347	        let path = entry.unwrap().path();
348	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
349	            continue;
350	        }
351	        let dot = std::fs::read_to_string(&path).unwrap();
352	        total += 1;
353	        let out = std::panic::catch_unwind(|| to_dot(&parse(&dot)))
354	            .unwrap_or_else(|_| String::from("<PANIC>"));
355	        if out == dot {
356	            ok += 1;
357	        } else if fails.len() < 20 {
358	            fails.push(path.file_name().unwrap().to_string_lossy().into_owned());
359	        }
360	    }
361	    eprintln!("corpus round-trip: {ok}/{total} byte-exact");
362	    for f in &fails {
363	        eprintln!("  MISMATCH: {f}");
364	    }
365	    assert_eq!(ok, total, "{} of {} payloads failed to round-trip", total - ok, total);
366	}
