    while i<len(raw):
        l=raw[i]
        if 'shape="plain"' in l and not l.rstrip().endswith('];'):
            buf=l; i+=1
            while True:
                buf+='\n'+raw[i]
                if raw[i].rstrip().endswith('];'): break
                i+=1
            out.append(buf); i+=1
        else:
            out.append(l); i+=1
    return out

def node_lines(dot):
    # top-level + nested node statements, in file order
    res=[]
    for l in logical(dot):
        s=l.strip()
        m=re.match(r'^(n\d+)\[', s)
        if m: res.append((m.group(1), s))
