//! Global `n<K>` node-id / port allocation (BEHAVIOR.md §3e).
//!
//! Observed rule, byte-consistent over **all 12 022** corpus graphs
//! (`mine_ids.py`, 12022/12022): the graph uses one monotonic counter starting
//! at 0, and identifiers are handed out in **emission order** so that id order ==
//! file order. For each node, in order:
//!   * a **record** first consumes one id per record *cell* (its `<port>`s), in
//!     cell order (premises, then the info cell, then conclusions), and then one
//!     more id for the node itself — so a record with `k` cells occupies ids
//!     `p, p+1, …, p+k-1` (ports) and `p+k` (node);
//!   * every other node kind (**ellipse**, **plain** legend, **invtrapezium**, …)
//!     consumes exactly one id, the node id.
//!
//! Example (`n7` from a real graph): 4 premise + 1 info + 3 conclusion cells take
//! ports `n0…n6`, then the node is `n7`; the next ellipse is `n8`. The scheme is
//! independent of the term contents; it depends only on the emission order and
//! each node's cell count.

/// A single monotonic `n<K>` id source implementing the observed allocation.
#[derive(Debug, Default, Clone)]
pub struct NodeIdAllocator {
    next: usize,
}

impl NodeIdAllocator {
    pub fn new() -> Self {
        Self { next: 0 }
    }

    /// The next raw id value that would be handed out (for assertions/tests).
    pub fn peek(&self) -> usize {
        self.next
    }

    /// Take one id, formatted `n<K>`.
    fn take(&mut self) -> String {
        let s = format!("n{}", self.next);
        self.next += 1;
        s
    }

    /// Allocate ids for a **record** with `n_cells` cells: returns the `n_cells`
    /// port ids (in cell order) followed by the node id. Ports precede the node,
    /// matching the observed scheme.
    pub fn record(&mut self, n_cells: usize) -> RecordIds {
        let ports = (0..n_cells).map(|_| self.take()).collect();
        let node = self.take();
        RecordIds { ports, node }
    }

    /// Allocate the single id of a non-record node (ellipse / plain / shaped).
    pub fn node(&mut self) -> String {
        self.take()
    }
}

/// The ids a record occupies: one `port` per cell, then the `node` id.
#[derive(Debug, Clone)]
pub struct RecordIds {
    pub ports: Vec<String>,
    pub node: String,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn record_takes_ports_then_node() {
        let mut a = NodeIdAllocator::new();
        // A record with 8 cells (4 prem + 1 info + 3 concl): ports n0..n7, node n8.
        let r = a.record(8);
        assert_eq!(r.ports, ["n0", "n1", "n2", "n3", "n4", "n5", "n6", "n7"]);
        assert_eq!(r.node, "n8");
        // next ellipse is n9.
        assert_eq!(a.node(), "n9");
    }

    #[test]
    fn interleaved_matches_observed_sequence() {
        // Reproduce the id sequence of the real graph in BEHAVIOR.md §3e:
        // record(8)->n8, ellipse->n9, ellipse->n?, record(5)->n15, ...
        let mut a = NodeIdAllocator::new();
        assert_eq!(a.record(8).node, "n8");
        assert_eq!(a.node(), "n9"); // ellipse
        assert_eq!(a.node(), "n10"); // ellipse
        let r = a.record(5); // ports n11..n15? no: n11..n15 is 5 -> node n16
        assert_eq!(r.ports, ["n11", "n12", "n13", "n14", "n15"]);
        assert_eq!(r.node, "n16");
    }
}

//! Record-cell rendering (BEHAVIOR.md §3a, §3f): turning facts / rule instances
//! into the exact text that goes inside a record cell, including the observed
//! escaping, the fact-vs-function spacing, and the `\l`/`&nbsp;` line-wrapping
//! FORMAT.
//!
//! What is byte-exact here (verified against the corpus):
//!   * **Escaping** of record-label metacharacters `< > { } |`.
//!   * **Fact spacing** `Name( a, b )` (a space after `(` and before `)`) versus
//!     **function spacing** `f(a, b)` (no inner spaces) — mined over the corpus;
//!     a fact / relation symbol pads, an ordinary function application does not.
//!   * **Info-cell** shape `#<temporal> : <RuleName>` optionally followed by
//!     `[<action>, …]`.
//!   * The **wrap alignment**: a broken group's continuation lines are indented
//!     with `&nbsp;` runs to the column of the group's first element — i.e. just
//!     after `( ` for a fact, after `<` for a tuple, after `[` for an action list
//!     (verified across 188 192 wrapped cells: the indent always equals that
//!     first-element column). Physical segments are separated by `\l`.
//!
//! What is a documented GAP (pretty-printer internal, not derivable from output):
//! *when* the renderer chooses to break — the line-width budget and the group
//! nesting that drive it (BEHAVIOR.md §3a). The flat renderer below reproduces
//! every UN-wrapped cell exactly; [`fill`] reproduces the wrap FORMAT for a given
//! break decision but does not itself decide the breaks.

use crate::term::Term;

/// Escape the metacharacters that are special inside a graphviz record label:
/// `< > { } |` each get a leading backslash. Everything else (including single
/// quotes, `~ $ ^ * ⊕`, spaces) is literal. Observed in every record cell.
pub fn escape_record(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '<' | '>' | '{' | '}' | '|' => {
                out.push('\\');
                out.push(c);
            }
            _ => out.push(c),
        }
    }
    out
}

/// A fact / relation atom occupying one premise or conclusion cell, e.g.
/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
/// for a persistent fact); `args` are its term arguments.
#[derive(Clone, Debug)]
pub struct Fact {
    pub name: String,
    pub args: Vec<Term>,
}

impl Fact {
    pub fn new(name: &str, args: Vec<Term>) -> Self {
        Fact { name: name.to_string(), args }
    }

    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
    pub fn render_flat(&self) -> String {
        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
        format!("{}( {} )", self.name, inner.join(", "))
    }

    /// Flat rendering with abbreviations applied to registered sub-terms
    /// (`table` maps a term's full rendering to its abbreviation name).
    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
        format!("{}( {} )", self.name, inner.join(", "))
    }
}

/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
    if actions.is_empty() {
        format!("#{} : {}", temporal, rule)
    } else {
        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
    }
}

/// Lay `items` out as a **fill** to a target `width`, starting at column
/// `open_col` (the alignment column of the group's first element). Returns the
/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
///
/// Greedy fill: keep appending `sep`-joined items to the current line while it
/// fits in `width`; otherwise start a new line. This reproduces the observed
/// packing (several short arguments share a line, then a break) **given** the
/// width; the width itself is the documented gap.
pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
    if items.is_empty() {
        return vec![String::new()];
    }
    let mut lines: Vec<String> = Vec::new();
    let mut cur = String::new();
    let mut col = open_col;
    for (i, it) in items.iter().enumerate() {
        let piece = if cur.is_empty() {
            it.clone()
        } else {
            format!("{}{}", sep, it)
        };
        if !cur.is_empty() && col + piece.chars().count() > width {
            lines.push(std::mem::take(&mut cur));
            col = open_col;
            cur.push_str(it);
            col += it.chars().count();
        } else {
            cur.push_str(&piece);
            col += piece.chars().count();
        }
        let _ = i;
    }
    lines.push(cur);
    lines
}

/// Join physical `lines` (from [`fill`]) into a single record-cell string using
/// the observed wrap format: lines separated by `\l`, every continuation line
/// prefixed by `open_col` `&nbsp;` entities (the verified alignment indent). The
/// caller is responsible for escaping the line contents first (via
/// [`escape_record`]) — the `\l` and `&nbsp;` are literal control sequences and
/// must not be escaped.
pub fn join_wrapped(lines: &[String], open_col: usize) -> String {
    let indent = "&nbsp;".repeat(open_col);
    let mut out = String::new();
    for (i, ln) in lines.iter().enumerate() {
        if i > 0 {
            out.push_str("\\l");
            out.push_str(&indent);
        }
        out.push_str(ln);
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn escape_record_metachars() {
        assert_eq!(escape_record("<$A, $A, 'g'^~ex>"), "\\<$A, $A, 'g'^~ex\\>");
        assert_eq!(escape_record("a|b{c}"), "a\\|b\\{c\\}");
        assert_eq!(escape_record("no meta 'g'^~x"), "no meta 'g'^~x");
    }

    #[test]
    fn fact_flat_spacing_matches_corpus() {
        // Fr( ~ex )  — a fact pads inside its parens.
        assert_eq!(Fact::new("Fr", vec![Term::fresh("ex")]).render_flat(), "Fr( ~ex )");
        // zero-arg fact: NoA( )
        assert_eq!(Fact::new("NoA", vec![]).render_flat(), "NoA( )");
        // Out( pk(~ltkA) ) — outer fact pads; inner function pk(...) does NOT.
        let f = Fact::new("Out", vec![Term::app("pk", vec![Term::fresh("ltkA")])]);
        assert_eq!(f.render_flat(), "Out( pk(~ltkA) )");
        // !SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )
        let f = Fact::new(
            "!SessionKey",
            vec![
                Term::tuple(vec![Term::pubv("A"), Term::pubv("A"), Term::exp(Term::cst("g"), Term::fresh("ex"))]),
                Term::pubv("A"),
                Term::fresh("ex"),
            ],
        );
        assert_eq!(f.render_flat(), "!SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )");
    }

    #[test]
    fn info_cell_shape() {
        assert_eq!(render_info("vf.5", "Fresh", &[]), "#vf.5 : Fresh");
        let acts = vec![Fact::new("RegKey", vec![Term::pubv("R.4")])];
        assert_eq!(render_info("vr.9", "generate_ltk", &acts), "#vr.9 : generate_ltk[RegKey( $R.4 )]");
    }

    #[test]
    fn wrap_format_alignment_is_first_element_column() {
        // Reproduce the observed cell (info action list of Corrupt_SessionKey):
        //   #vr.2 : Corrupt_SessionKey[Corrupt( $A ),\l<27 nbsp>BeforeExpire( <$A, $A, 'g'^~ex> )]\l
        // open_col = len("#vr.2 : Corrupt_SessionKey[") = 27.
        let prefix = "#vr.2 : Corrupt_SessionKey[";
        assert_eq!(prefix.chars().count(), 27);
        let a1 = "Corrupt( $A ),";
        let a2 = escape_record("BeforeExpire( <$A, $A, 'g'^~ex> )]");
        let body = join_wrapped(&[a1.to_string(), a2], 27);
        let expected = "Corrupt( $A ),\\l\
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\
BeforeExpire( \\<$A, $A, 'g'^~ex\\> )]";
        assert_eq!(body, expected);
    }

    #[test]
    fn fill_packs_greedily_to_width() {
        // Two short items that fit share a line; a third that overflows wraps.
        let items = vec!["aa".to_string(), "bb".to_string(), "cccccc".to_string()];
        let lines = fill(&items, ", ", 4, 12);
        // col starts at 4: "aa"(6) + ", bb"(10) fits <=12; ", cccccc" -> 18 > 12, wrap.
        assert_eq!(lines, vec!["aa, bb", "cccccc"]);
    }
}

//! Graph GENERATION (BEHAVIOR.md §6): mapping a proof-state / constraint-system
//! description onto the DOT [`Graph`] model, over an independent input model
//! designed from observed paired `main/proof` sequents and `interactive-graph-def`
//! graphs.
//!
//! What the observed system→graph mapping does, structurally (each point traces to
//! corpus/live observation — see BEHAVIOR.md §6):
//!   * a **rule instance** `#t : Rule[actions]` becomes a `record` node with up to
//!     three groups `{premises}|{info}|{conclusions}`; the **info** group (the
//!     `#t : Rule[…]` cell) is always present (100 % of 160 409 corpus records),
//!     and an **empty** premise or conclusion group is dropped (so a source rule
//!     with no premises renders `{info}|{concl}`);
//!   * an intruder-knowledge fact renders as a gray `!KU( m ) @ #t` **ellipse**;
//!     a protocol action/event as a darkblue `Fact @ #t` ellipse; a compressed
//!     intruder rule as an uncolored `#t : rule` ellipse;
//!   * an unresolved node referenced by an open premise renders as an
//!     **invtrapezium** `(#var, idx)` (BEHAVIOR.md §3d);
//!   * **edges** connect a conclusion port to a premise port (structural), or an
//!     intruder deduction (red dashed), message (gray30), temporal order (blue3 /
//!     black dashed), etc. — the finite observed style vocabulary (§3c);
//!   * `n<K>` ids come from [`crate::alloc`]; the header is inferred by role (§4).
//!
//! GAPS (need the GPL solver; not derivable from output): *which* nodes/edges a
//! raw constraint system yields (the compression content), the per-rule color
//! hash, and record-cell line wrapping. This layer takes node/edge lists, colors,
//! and pre-rendered cell text as INPUTS and assembles the exact DOT structure.

use crate::alloc::NodeIdAllocator;
use crate::model::*;
use crate::render::{escape_record, Fact};

/// A rule instance: one record node with premise / info / conclusion cells.
#[derive(Clone, Debug)]
pub struct RuleInstance {
    pub temporal: String,
    pub rule: String,
    pub role: String,
    pub premises: Vec<Fact>,
    pub actions: Vec<Fact>,
    pub conclusions: Vec<Fact>,
    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
    pub fillcolor: String,
    /// `black` on the light MSR palette, `white` on the saturated role palette.
    pub fontcolor: String,
}

impl RuleInstance {
    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
        RuleInstance {
            temporal: temporal.into(),
            rule: rule.into(),
            role: Role::UNDEFINED.into(),
            premises: Vec::new(),
            actions: Vec::new(),
            conclusions: Vec::new(),
            fillcolor: fillcolor.into(),
            fontcolor: "black".into(),
        }
    }
    pub fn premises(mut self, f: Vec<Fact>) -> Self {
        self.premises = f;
        self
    }
    pub fn actions(mut self, f: Vec<Fact>) -> Self {
        self.actions = f;
        self
    }
    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
        self.conclusions = f;
        self
    }
    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
        self.role = r.into();
        self.fontcolor = fontcolor.into();
        self
    }
    fn cell_count(&self) -> usize {
        let p = self.premises.len();
        let c = self.conclusions.len();
        p + 1 /* info */ + c
    }
}

/// One node of the input system, in emission order.
#[derive(Clone, Debug)]
pub enum GraphNode {
    Rule(RuleInstance),
    /// `!KU( term ) @ #t` — intruder knowledge (drawn as a gray ellipse). `term`
    /// is the pre-rendered message text.
    Knowledge { term: String, temporal: String },
    /// `Fact @ #t` — a protocol action/event (darkblue ellipse). `fact` is
    /// pre-rendered.
    Action { fact: String, temporal: String },
    /// `#t : rule` — a compressed rule shown as a single uncolored ellipse.
    Compressed { temporal: String, rule: String },
    /// `(#var, idx)` — an unresolved node referenced by an open premise
    /// (invtrapezium).
    OpenTarget { node_var: String, premise_index: usize },
}

/// An endpoint reference into the input system (resolved to `n<K>[:n<port>]`).
#[derive(Clone, Copy, Debug)]
pub enum EndRef {
    /// The whole node (no port) — ellipses, invtrapezium, legend.
    Whole(usize),
    /// Conclusion `c` of rule node `n` (→ its conclusion port).
    Conclusion(usize, usize),
    /// Premise `p` of rule node `n` (→ its premise port).
    Premise(usize, usize),
}

/// The finite observed edge-style vocabulary (BEHAVIOR.md §3c). Each maps to a
/// fixed attribute list emitted verbatim.
#[derive(Clone, Copy, Debug)]
pub enum EdgeStyle {
    /// `style="bold",weight="10.0",color="gray50"` — structural, into a target.
    StructuralGray,
    /// `style="bold",weight="10.0"` — structural (uncolored).
    Structural,
    /// `color="gray30"` — message / standard edge.
    Message,
    /// `color="red",style="dashed"` — intruder `!KU` deduction.
    KnowledgeDeduction,
    /// `color="orangered2"` — deduction variant.
    Deduction,
    /// `color="blue3",style="dashed"` — temporal-order edge.
    TemporalBlue,
    /// `color="black",style="dashed"` — before / less-than temporal edge.
    TemporalBlack,
    /// `style="invis"` — ranking edge to the legend.
    Invis,
}

impl EdgeStyle {
    /// The exact attribute pairs, in observed key order.
    pub fn attrs(self) -> Vec<(String, String)> {
        let raw: &[(&str, &str)] = match self {
            EdgeStyle::StructuralGray => {
                &[("style", "bold"), ("weight", "10.0"), ("color", "gray50")]
            }
            EdgeStyle::Structural => &[("style", "bold"), ("weight", "10.0")],
            EdgeStyle::Message => &[("color", "gray30")],
            EdgeStyle::KnowledgeDeduction => &[("color", "red"), ("style", "dashed")],
            EdgeStyle::Deduction => &[("color", "orangered2")],
            EdgeStyle::TemporalBlue => &[("color", "blue3"), ("style", "dashed")],
            EdgeStyle::TemporalBlack => &[("color", "black"), ("style", "dashed")],
            EdgeStyle::Invis => &[("style", "invis")],
        };
        raw.iter().map(|(k, v)| (k.to_string(), v.to_string())).collect()
    }
}

/// An edge in the input system.
#[derive(Clone, Debug)]
pub struct SysEdge {
    pub src: EndRef,
    pub dst: EndRef,
    pub style: EdgeStyle,
}

impl SysEdge {
    pub fn new(src: EndRef, dst: EndRef, style: EdgeStyle) -> Self {
        SysEdge { src, dst, style }
    }
}

/// A proof-state graph description: nodes in emission order, edges, and an
/// optional pre-rendered legend (inner HTML of the `plain` node) plus the invis
/// edges wiring it in.
#[derive(Clone, Debug, Default)]
pub struct System {
    pub nodes: Vec<GraphNode>,
    pub edges: Vec<SysEdge>,
    /// Legend inner HTML (from [`crate::abbrev::Abbreviator::legend_html`]); if
    /// non-empty a `{ rank="sink"; … }` block is appended.
    pub legend_html: Option<String>,
    /// Invis edges to the legend node (emitted after the sink block).
    pub legend_edges: Vec<(EndRef, ())>,
}

/// Resolved ids for one system node.
enum Resolved {
    Record { ports_prem: Vec<String>, port_info: String, ports_concl: Vec<String>, node: String },
    Node(String),
}

impl Resolved {
    fn node_id(&self) -> &str {
        match self {
            Resolved::Record { node, .. } => node,
            Resolved::Node(id) => id,
        }
    }
}

/// Build the DOT [`Graph`] for a [`System`]: allocate ids, emit nodes in order,
/// then edges, then the legend sink-block + its invis edges. Header is inferred
/// from roles.
pub fn generate(sys: &System) -> Graph {
    let mut alloc = NodeIdAllocator::new();
    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
    let mut g = Graph::new(Header::Simple);

    // Pass 1: allocate ids and emit node statements in emission order.
    for node in &sys.nodes {
        match node {
            GraphNode::Rule(r) => {
                let ids = alloc.record(r.cell_count());
                let mut it = ids.ports.into_iter();
                let ports_prem: Vec<String> = (0..r.premises.len()).map(|_| it.next().unwrap()).collect();
                let port_info = it.next().unwrap();
                let ports_concl: Vec<String> = (0..r.conclusions.len()).map(|_| it.next().unwrap()).collect();
                let rec = build_record(r, &ports_prem, &port_info, &ports_concl);
                g.push(Stmt::Node(Node::record(ids.node.clone(), rec)));
                resolved.push(Resolved::Record { ports_prem, port_info, ports_concl, node: ids.node });
            }
            GraphNode::Knowledge { term, temporal } => {
                let id = alloc.node();
                let label = format!("!KU( {} ) @ #{}", term, temporal);
                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray"))));
                resolved.push(Resolved::Node(id));
            }
            GraphNode::Action { fact, temporal } => {
                let id = alloc.node();
                let label = format!("{} @ #{}", fact, temporal);
                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue"))));
                resolved.push(Resolved::Node(id));
            }
            GraphNode::Compressed { temporal, rule } => {
                let id = alloc.node();
                let label = format!("#{} : {}", temporal, rule);
                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label))));
                resolved.push(Resolved::Node(id));
            }
            GraphNode::OpenTarget { node_var, premise_index } => {
                let id = alloc.node();
                g.push(Stmt::Node(Node::shaped(
                    id.clone(),
                    Shaped::invtrapezium(node_var, *premise_index),
                )));
                resolved.push(Resolved::Node(id));
            }
        }
    }

    // Pass 2: edges.
    for e in &sys.edges {
        let src = endpoint(&resolved, e.src);
        let dst = endpoint(&resolved, e.dst);
        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
    }

    // Pass 3: legend sink-block, then its invis edges (observed order).
    if let Some(html) = &sys.legend_html {
        if !html.is_empty() {
            let legend_id = alloc.node();
            let block = RankBlock {
                rank: "sink".into(),
                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
            };
            g.push(Stmt::RankBlock(block));
            for (from, ()) in &sys.legend_edges {
                let src = endpoint(&resolved, *from);
                g.push(Stmt::Edge(Edge {
                    src,
                    dst: EndPoint::node(legend_id.clone()),
                    attrs: EdgeStyle::Invis.attrs(),
                }));
            }
        }
    }

    g.set_inferred_header();
    g
}

/// Assemble a record node's model from a rule instance and its allocated ports.
/// Empty premise / conclusion groups are dropped; the info group is always kept
/// (matches the observed group structure).
fn build_record(r: &RuleInstance, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
    let mut columns: Vec<Vec<Cell>> = Vec::new();
    if !r.premises.is_empty() {
        columns.push(cells(&r.premises, ports_prem));
    }
    let info_text = crate::render::render_info(&r.temporal, &r.rule, &r.actions);
    columns.push(vec![Cell::new(port_info, escape_record(&info_text))]);
    if !r.conclusions.is_empty() {
        columns.push(cells(&r.conclusions, ports_concl));
    }
    Record {
        columns,
        fillcolor: r.fillcolor.clone(),
        fontcolor: r.fontcolor.clone(),
        role: Role(r.role.clone()),
    }
}

fn cells(facts: &[Fact], ports: &[String]) -> Vec<Cell> {
    facts
        .iter()
        .zip(ports)
        .map(|(f, p)| Cell::new(p.clone(), escape_record(&f.render_flat())))
        .collect()
}

/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
    match r {
        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
        EndRef::Conclusion(n, c) => {
            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
                EndPoint::port(node.clone(), ports_concl[c].clone())
            } else {
                EndPoint::node(resolved[n].node_id().to_string())
            }
        }
        EndRef::Premise(n, p) => {
            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
                EndPoint::port(node.clone(), ports_prem[p].clone())
            } else {
                EndPoint::node(resolved[n].node_id().to_string())
            }
        }
    }
}

//! Graph simplification / abbreviation options (BEHAVIOR.md §5, §7).
//!
//! The web UI exposes four "Graph simplification" levels (`lvl0`..`lvl3`
//! toggles: *off*, *L1*, *L2*, *L3*) plus an abbreviation toggle. These are not
//! separate endpoints — the client JS stores them in cookies and appends them as
//! **query parameters** to the graph URL. The observed parameter set (mined from
//! the UI JS and confirmed by live probes; see QUERIES.log) is:
//!
//! | param            | when the UI sends it            | server-side effect (observed)             |
//! |------------------|---------------------------------|-------------------------------------------|
//! | `simplification=N` | always (N = level, default 2) | selects the level; N alone changed **no** probed graph (L1≡L2≡L3 byte-identical) |
//! | `uncompact`      | only at level 0                 | disables node COMPACTION                  |
//! | `uncompress`     | only at level 0                 | disables system COMPRESSION               |
//! | `unabbreviate`   | when the abbreviate cookie is off | disables the abbreviation pass          |
//! | `no-auto-sources`| when auto-sources cookie is off | disables auto-source-lemma precomputation |
//! | `clustering=true`| when clustering cookie is on    | forces role clustering                    |
//!
//! Observed transforms (live diffs, NAXOS/NSLPK3 case graphs):
//!   * **compression** (on unless `uncompress`): Fresh rules (`Fr( ~x )` sources)
//!     and single intruder-derivation rules are hidden / collapsed — `!KU` facts
//!     become gray ellipses and Fresh sources disappear; turning it OFF re-expands
//!     them into full `record` rule nodes (node/edge counts grow markedly).
//!   * **compaction** (on unless `uncompact`): a lone intruder `isend`/`coerce`
//!     rule is drawn as a single ellipse (e.g. `#vf.7 : isend`); OFF draws it as a
//!     full `{!KU(m)}|{#vf : isend[K(m)]}|{In(m)}` record.
//!   * **abbreviation** (on unless `unabbreviate`): complex sub-terms are replaced
//!     by legend names and a `{ rank="sink"; … }` legend block is emitted; OFF
//!     inlines every term in full and omits the legend block entirely.
//!
//! The default (no query params, as the corpus was crawled) equals level ≥1:
//! compressed + compacted + abbreviated. The distinction between L1/L2/L3 was not
//! reproduced on any probed graph and is a documented GAP — as is the *content* of
//! compression/compaction, which needs the GPL solver (this crate models the
//! flags and the abbreviation on/off transform, taking the node set as input).

/// The observed graph-rendering options. `abbreviate` is the one transform this
/// crate applies directly (drop the legend + inline terms when false); the
/// compress/compact flags are recorded and documented — their *content* is a
/// solver-side GAP, so a caller supplies the already-(un)compressed node set.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Options {
    /// Graph simplification level 0..=3 (UI default 2).
    pub level: u8,
    /// Run the abbreviation pass (emit a legend). `false` ⇒ `unabbreviate`.
    pub abbreviate: bool,
    /// Apply node compaction. `false` ⇒ `uncompact` (sent by the UI at level 0).
    pub compact: bool,
    /// Apply system compression. `false` ⇒ `uncompress` (sent by the UI at level 0).
    pub compress: bool,
    /// Force role clustering (`clustering=true`).
    pub clustering: bool,
}

impl Default for Options {
    /// The corpus/default rendering: level 2, abbreviated, compacted, compressed.
    fn default() -> Self {
        Options { level: 2, abbreviate: true, compact: true, compress: true, clustering: false }
    }
}

impl Options {
    /// The UI's level-0 preset: compaction and compression OFF (the UI sends
    /// `uncompact` + `uncompress` + `simplification=0`).
    pub fn level0() -> Self {
        Options { level: 0, compact: false, compress: false, ..Options::default() }
    }

    /// Reconstruct the query string the UI appends for these options, in the
    /// UI's parameter order (`uncompact`, `uncompress` first — only at level 0 —
    /// then `unabbreviate`, then `simplification`, then `clustering`). Returns the
    /// part after `?` (empty if nothing would be appended). Byte-shaped to match
    /// the observed `?uncompact=&uncompress=&simplification=0` form.
    pub fn query_string(&self) -> String {
        let mut parts: Vec<String> = Vec::new();
        if self.level == 0 {
            parts.push("uncompact=".into());
            parts.push("uncompress=".into());
        }
        if !self.abbreviate {
            parts.push("unabbreviate=".into());
        }
        parts.push(format!("simplification={}", self.level));
        if self.clustering {
            parts.push("clustering=true".into());
        }
        parts.join("&")
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn default_query_is_level_2() {
        assert_eq!(Options::default().query_string(), "simplification=2");
    }

    #[test]
    fn level0_sends_uncompact_uncompress() {
        // Matches the live URL that produced the expanded graph:
        //   ?uncompact=&uncompress=&simplification=0
        assert_eq!(Options::level0().query_string(), "uncompact=&uncompress=&simplification=0");
    }

    #[test]
    fn unabbreviate_param() {
        let o = Options { abbreviate: false, ..Options::default() };
        assert_eq!(o.query_string(), "unabbreviate=&simplification=2");
    }

    #[test]
    fn raw_all_off() {
        let o = Options { level: 0, abbreviate: false, compact: false, compress: false, clustering: false };
        assert_eq!(o.query_string(), "uncompact=&uncompress=&unabbreviate=&simplification=0");
    }
}

